+                github: {
+                  command: "npx",
+                  args: ["-y", "@modelcontextprotocol/server-github"],
+                  env: {
+                    GITHUB_TOKEN: envRef("GITHUB_TOKEN"),
+                    PLAIN_VAR: "plain-value",
+                  },
+                },
+              },
+            },
+          },
+        },
+      },
+    });
+    const context = makeContext(config);
+    const defaults: SecretDefaults = undefined;
